function GradientPicker() {
  const [color1, setColor1] = React.useState('#3b82f6');
  const [color2, setColor2] = React.useState('#8b5cf6');
  const [angle, setAngle] = React.useState(135);
  const [copied, setCopied] = React.useState(false);

  const css = `linear-gradient(${angle}deg, ${color1}, ${color2})`;

  const copy = () => {
    navigator.clipboard.writeText(`background: ${css};`);
    setCopied(true);
    setTimeout(() => setCopied(false), 1500);
  };

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#ffffff', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column', color: '#1e293b' }}>
      <h2 style={{ margin: '0 0 12px', fontSize: 18 }}>Gradient Picker</h2>
      <div style={{ height: 100, borderRadius: 8, marginBottom: 12, background: css }} />
      <div style={{ display: 'flex', gap: 12, marginBottom: 12 }}>
        <div style={{ flex: 1 }}>
          <label style={{ fontSize: 12, fontWeight: 500 }}>Color 1</label>
          <input type="color" value={color1} onChange={e => setColor1(e.target.value)} style={{ width: '100%', height: 36, border: 'none', cursor: 'pointer' }} />
        </div>
        <div style={{ flex: 1 }}>
          <label style={{ fontSize: 12, fontWeight: 500 }}>Color 2</label>
          <input type="color" value={color2} onChange={e => setColor2(e.target.value)} style={{ width: '100%', height: 36, border: 'none', cursor: 'pointer' }} />
        </div>
      </div>
      <label style={{ fontSize: 12, fontWeight: 500 }}>Angle: {angle}°</label>
      <input type="range" min="0" max="360" value={angle} onChange={e => setAngle(Number(e.target.value))} style={{ marginBottom: 12 }} />
      <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginTop: 'auto' }}>
        <code style={{ flex: 1, background: '#f1f5f9', padding: 8, borderRadius: 6, fontSize: 12, overflow: 'hidden', textOverflow: 'ellipsis' }}>{css}</code>
        <button onClick={copy} style={{ padding: '8px 14px', borderRadius: 6, border: 'none', background: copied ? '#059669' : '#2563eb', color: '#fff', fontSize: 13, cursor: 'pointer' }}>{copied ? 'Copied!' : 'Copy'}</button>
      </div>
    </div>
  );
}
render(<GradientPicker/>);
